CREATE DATABASE IF NOT EXISTS placement_db;
USE placement_db;
DROP TABLE IF EXISTS students;

CREATE TABLE students (

    id INT PRIMARY KEY AUTO_INCREMENT,

    name VARCHAR(100),

    roll_no VARCHAR(50),

    class_name VARCHAR(50),

    course VARCHAR(50),

    subcourse VARCHAR(50),

    cgpa FLOAT,

    attendance FLOAT,

    internships INT,

    technical FLOAT,

    communication FLOAT,

    backlogs INT,

    placed INT,

    probability FLOAT
);



SHOW TABLES;
DESCRIBE student_data;

SELECT COUNT(*) FROM students;
SELECT * FROM students LIMIT 10;

SELECT COUNT(*) FROM students;
SELECT COUNT(*) FROM students WHERE placement_status = 1;
SELECT COUNT(*) FROM students WHERE placement_status = 0;

SELECT
COUNT(*) AS total,
SUM(placed) AS placed_count
FROM students;

SELECT
COUNT(*) AS total,
SUM(placement_status) AS placement_status_count
FROM students;

SELECT
placed,
placement_status,
name,
cgpa
FROM students
LIMIT 10;

SELECT COUNT(*) FROM student_data;

SELECT
COUNT(*) AS total,
SUM(placed) AS placed_count
FROM student_data;

SELECT
COUNT(*) AS total,
SUM(placement_status) AS placement_status_count
FROM student_data;

SELECT
placed,
placement_status,
name,
cgpa
FROM student_data
LIMIT 10;

UPDATE student_data
SET placed = placement_status;